1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	export interface QuoteStep {
13	  op: "quote";
14	  items: Item[];
15	}
16	
17	export interface Damage {
18	  itemType: string;
19	  amount: number;
20	}
21	
22	export interface Incident {
23	  cause: string;
24	  damages: Damage[];
25	}
26	
27	export interface ClaimStep {
28	  op: "claim";
29	  policy: number;
30	  incident: Incident;
31	}
32	
33	export type Step = QuoteStep | ClaimStep;
34	
35	export interface Scenario {
36	  customer: Customer;
37	  steps: Step[];
38	}
39	
40	export interface QuoteResult {
41	  premium: number;
42	}
43	
44	export interface ClaimResult {
45	  payout: number;
46	  remainingCap: number;
47	}
48	
49	export type StepResult = QuoteResult | ClaimResult;
50	
51	export interface ScenarioOutput {
52	  results: StepResult[];
53	}
54	
55	const PROCESSING_FEE = 5;
56	const BLOCK_SIZE = 3;
57	const COMPONENT_BLOCK_PRICE = 60;
58	const DEDUCTIBLE = 100;
59	const CAP_MULTIPLIER = 2;
60	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
61	const HIGH_ENCHANTMENT_CLAIM_RATE = 0.5;
62	const CURSED_SURCHARGE_RATE = 0.5;
63	const HIGH_ENCHANTMENT_RATE = 0.3;
64	const HIGH_ENCHANTMENT_THRESHOLD = 5;
65	const FIRST_INSURANCE_RATE = 0.1;
66	const LOYALTY_DISCOUNT_RATE = 0.2;
67	const LOYALTY_YEARS_THRESHOLD = 2;
68	const FOLLOWUP_DISCOUNT_RATE = 0.15;
69	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
70	  sword: 100,
71	  amulet: 60,
72	  staff: 80,
73	  potion: 40,
74	  rune: 25,
75	  moonstone: 25,
76	};
77	
78	const INSURANCE_VALUE_BY_TYPE: Record<string, number> = {
79	  sword: 1000,
80	  amulet: 600,
81	  staff: 800,
82	  potion: 400,
83	  rune: 250,
84	  moonstone: 250,
85	};
86	
87	const insuranceValue = (item: Item): number =>
88	  INSURANCE_VALUE_BY_TYPE[item.type] ?? 0;
89	
90	const insuranceSum = (items: Item[]): number =>
91	  items.reduce((sum, item) => sum + insuranceValue(item), 0);
92	
93	const basePremium = (item: Item): number =>
94	  BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
95	
96	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
97	
98	const groupByType = (items: Item[]): Map<string, Item[]> => {
99	  const groups = new Map<string, Item[]>();
100	  for (const item of items) {
101	    const existing = groups.get(item.type) ?? [];
102	    existing.push(item);
103	    groups.set(item.type, existing);
104	  }
105	  return groups;
106	};
107	
108	const sumBasePremiums = (items: Item[]): number =>
109	  items.reduce((sum, item) => sum + basePremium(item), 0);
110	
111	const isCompleteComponentBlock = (type: string, group: Item[]): boolean =>
112	  group.length === BLOCK_SIZE && COMPONENT_TYPES.has(type);
113	
114	const groupTotal = (type: string, group: Item[]): number =>
115	  isCompleteComponentBlock(type, group)
116	    ? COMPONENT_BLOCK_PRICE
117	    : sumBasePremiums(group);
118	
119	const policyBase = (items: Item[]): number =>
120	  Array.from(groupByType(items)).reduce(
121	    (sum, [type, group]) => sum + groupTotal(type, group),
122	    0,
123	  );
124	
125	const perItemSurcharge = (
126	  items: Item[],
127	  predicate: (item: Item) => boolean,
128	  rate: number,
129	): number =>
130	  items.reduce(
131	    (sum, item) => sum + (predicate(item) ? basePremium(item) * rate : 0),
132	    0,
133	  );
134	
135	const isCursed = (item: Item): boolean => item.cursed === true;
136	
137	const enchantmentLevel = (item: Item): number => item.enchantment ?? 0;
138	
139	const isHighlyEnchanted = (item: Item): boolean =>
140	  enchantmentLevel(item) >= HIGH_ENCHANTMENT_THRESHOLD;
141	
142	const firstInsuranceSurcharge = (base: number): number =>
143	  base * FIRST_INSURANCE_RATE;
144	
145	const loyaltyDiscount = (base: number, customer: Customer): number =>
146	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
147	    ? base * LOYALTY_DISCOUNT_RATE
148	    : 0;
149	
150	const followupDiscount = (base: number, quoteIndex: number): number =>
151	  quoteIndex > 0 ? base * FOLLOWUP_DISCOUNT_RATE : 0;
152	
153	const totalSurcharges = (items: Item[], base: number): number =>
154	  perItemSurcharge(items, isCursed, CURSED_SURCHARGE_RATE) +
155	  perItemSurcharge(items, isHighlyEnchanted, HIGH_ENCHANTMENT_RATE) +
156	  firstInsuranceSurcharge(base);
157	
158	const totalDiscounts = (
159	  base: number,
160	  customer: Customer,
161	  quoteIndex: number,
162	): number =>
163	  loyaltyDiscount(base, customer) + followupDiscount(base, quoteIndex);
164	
165	const quotePremium = (
166	  items: Item[],
167	  customer: Customer,
168	  quoteIndex: number,
169	): number => {
170	  const base = policyBase(items);
171	  const adjusted =
172	    base +
173	    totalSurcharges(items, base) -
174	    totalDiscounts(base, customer, quoteIndex);
175	  return Math.ceil(adjusted) + PROCESSING_FEE;
176	};
177	
178	interface Policy {
179	  items: Item[];
180	  remainingCap: number;
181	}
182	
183	interface ScenarioState {
184	  customer: Customer;
185	  policies: Map<number, Policy>;
186	  quoteIndex: number;
187	  stepIndex: number;
188	}
189	
190	const validateItemTypes = (items: Item[]): void => {
191	  for (const item of items) {
192	    if (!(item.type in BASE_PREMIUM_BY_TYPE)) {
193	      throw new Error(`unknown item type: ${item.type}`);
194	    }
195	  }
196	};
197	
198	const processQuote = (step: QuoteStep, state: ScenarioState): QuoteResult => {
199	  validateItemTypes(step.items);
200	  state.policies.set(state.stepIndex, {
201	    items: step.items,
202	    remainingCap: insuranceSum(step.items) * CAP_MULTIPLIER,
203	  });
204	  const premium = quotePremium(step.items, state.customer, state.quoteIndex);
205	  state.quoteIndex += 1;
206	  return { premium };
207	};
208	
209	const reimbursementRate = (item: Item): number =>
210	  enchantmentLevel(item) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD
211	    ? HIGH_ENCHANTMENT_CLAIM_RATE
212	    : 1;
213	
214	const damagePayout = (damage: Damage, items: Item[]): number => {
215	  const item = items.find((it) => it.type === damage.itemType) as Item;
216	  return damage.amount * reimbursementRate(item) - DEDUCTIBLE;
217	};
218	
219	const countBy = <T>(items: T[], key: (item: T) => string): Map<string, number> => {
220	  const counts = new Map<string, number>();
221	  for (const item of items) {
222	    const k = key(item);
223	    counts.set(k, (counts.get(k) ?? 0) + 1);
224	  }
225	  return counts;
226	};
227	
228	const validateNonNegativeAmounts = (damages: Damage[]): void => {
229	  for (const damage of damages) {
230	    if (damage.amount < 0) {
231	      throw new Error(`claim damage amount must be non-negative`);
232	    }
233	  }
234	};
235	
236	const validateCoverage = (damages: Damage[], items: Item[]): void => {
237	  const itemCounts = countBy(items, (item) => item.type);
238	  const damageCounts = countBy(damages, (damage) => damage.itemType);
239	  for (const [type, count] of damageCounts) {
240	    if (count > (itemCounts.get(type) ?? 0)) {
241	      throw new Error(
242	        `claim damages exceed policy coverage for itemType ${type}`,
243	      );
244	    }
245	  }
246	};
247	
248	const validateDamages = (damages: Damage[], items: Item[]): void => {
249	  validateNonNegativeAmounts(damages);
250	  validateCoverage(damages, items);
251	};
252	
253	const sumDamagePayouts = (damages: Damage[], items: Item[]): number =>
254	  damages.reduce((sum, damage) => sum + damagePayout(damage, items), 0);
255	
256	const processClaim = (step: ClaimStep, state: ScenarioState): ClaimResult => {
257	  const policy = state.policies.get(step.policy) as Policy;
258	  validateDamages(step.incident.damages, policy.items);
259	  const rawPayout = sumDamagePayouts(step.incident.damages, policy.items);
260	  const payout = Math.floor(Math.min(rawPayout, policy.remainingCap));
261	  policy.remainingCap -= payout;
262	  return { payout, remainingCap: policy.remainingCap };
263	};
264	
265	const processStep = (step: Step, state: ScenarioState): StepResult =>
266	  step.op === "quote" ? processQuote(step, state) : processClaim(step, state);
267	
268	export const processScenario = (scenario: Scenario): ScenarioOutput => {
269	  const state: ScenarioState = {
270	    customer: scenario.customer,
271	    policies: new Map<number, Policy>(),
272	    quoteIndex: 0,
273	    stepIndex: 0,
274	  };
275	  const results: StepResult[] = scenario.steps.map((step, stepIndex) => {
276	    state.stepIndex = stepIndex;
277	    return processStep(step, state);
278	  });
279	  return { results };
280	};
